mapper.delete:
DELETE FROM stock_reservation
WHERE cl_order_id = #{clOrderId}
  AND product_id = #{productId}

mapper.select:
SELECT COALESCE(SUM(reserved_qty), 0)
FROM stock_reservation
WHERE cl_order_id = #{clOrderId}
  AND product_id = #{productId}

SELECT COALESCE(SUM(reserved_qty), 0)
FROM stock_reservation
WHERE product_id = #{productId}
  AND lot_no = #{lotNo}

SELECT COUNT(*) 
FROM stock_reservation 
WHERE cl_order_id = #{clOrderId}

SELECT sr.cl_order_id, sr.detail_id, sr.product_id, p.product_name, sr.lot_no, sr.reserved_qty, sr.reserved_at, sr.manager, c.client_name FROM stock_reservation sr JOIN product p ON sr.product_id = p.product_id JOIN client_order co ON sr.cl_order_id = co.cl_order_id JOIN client c ON co.client_id = c.client_id
( sr.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR c.client_name LIKE CONCAT('%', #{keyword}, '%') )
AND sr.reserved_at >= #{startDate}
AND sr.reserved_at <= #{endDate}
ORDER BY sr.reserved_at DESC LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM stock_reservation sr JOIN product p ON sr.product_id = p.product_id JOIN client_order co ON sr.cl_order_id = co.cl_order_id JOIN client c ON co.client_id = c.client_id
( sr.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR c.client_name LIKE CONCAT('%', #{keyword}, '%') )
AND sr.reserved_at >= #{startDate}
AND sr.reserved_at <= #{endDate}
